import numpy as np
from phe import paillier
from time import time
from rory.core.interfaces.cipherscheme_result import CipherschemeResult
from typing import Tuple,List
import numpy.typing as npt

"""
Description: 
	class to represent a symmetric encryption scheme
Attributes:
    _round: Flag to know if decryption needs to be rounded based on plaintext type
"""
class Paillier(object):

	"""
	Description: split a plaintext matrix into vectors
    """
	def encryptMatrix(plaintext_matrix:npt.NDArray, public_key:List[Tuple[float,float,float]]) -> CipherschemeResult:
		start_time = time()
		results = []
		for v in plaintext_matrix:
			result = Paillier.encryptVector(
				plaintext_vector = v,
				public_key       = public_key
			)
			results.append(result)
		end_time   = time()
		encryption_time = end_time-start_time
		return results

	"""
	description: split a plaintext vector into scalars
    """
	def encryptVector(plaintext_vector:npt.NDArray, public_key:List[Tuple[float,float,float]]) -> List[float]:
		results = []
		for v in plaintext_vector:
			result = Paillier.encryptScalar(
				plaintext  = v,
				public_key = public_key
			)
			results.append(result)
		return results


	"""
	description: Encrypt a plaintext using SK
	attributes:
		v: plaintext
		sk: secret key
		m: number of attributes of SK
	constraints:
		1. E1: sk[0][0] * sk[0][2] * v + sk[0][1] * self.R[m-1] + sk[0][0] * (self.R[0] - self.R[m-2])
		2. Ei: sk[i][0] * sk[i][2] * v + sk[i][1] * self.R[m-1] + sk[i][0] * (self.R[i] - self.R[i-1])
		3. Em: sk[m-1][0] + sk[m-1][1] + sk[m-1][2]) * self.R[m-1]
    """
	def encryptScalar(plaintext:float, public_key:List[Tuple[float,float,float]]) -> List: 
		return public_key.encrypt(plaintext)

	"""
	description: split a ciphertext matrix into vectors
    """
	def decryptMatrix(ciphertext_matrix:npt.NDArray, private_key:List[Tuple[float,float,float]]) -> CipherschemeResult:
		start_time = time()
		results = []
		for c in ciphertext_matrix:
			result = Paillier.decryptVector(
				ciphertext_vector = c,
				private_key = private_key
			)
			results.append(result)
		end_time   = time()
		decryption_time = end_time-start_time
		return results
		
		
	"""
	description: split a ciphertext vector into scalars
    """
	def decryptVector(ciphertext_vector:npt.NDArray, private_key:List[Tuple[float,float,float]]) -> List:
		results = []
		for c in ciphertext_vector:
			result = Paillier.decryptScalar(
				ciphertext = c,
				private_key = private_key
			)
			results.append(result)
		return results #[ self.decryptScalar(**new_kwargs(c)) for c in cs ]



	"""    
    description: Decrypt a ciphertext using SK
	attributes:
		E: ciphertext
		sk: secret key
		m: number of attributes of SK
	"""
	def decryptScalar(ciphertext:List, private_key:List[Tuple[float,float,float]]) -> float:  
		return private_key.decrypt(ciphertext)
	

	
if __name__ == "__main__":

	public_key, private_key = paillier.generate_paillier_keypair()
	plaintext = np.zeros((3,3))
	print(plaintext)
	cipher = Paillier.encryptMatrix(
		plaintext_matrix = plaintext,
		public_key       = public_key
	)
	print(cipher)

	plain = Paillier.decryptMatrix(
		ciphertext_matrix  = cipher,
		private_key = private_key
	)
	print(plain)